create table dirkspzm32.s_seaquist_send_bew (
    firma_nr   number(3, 0),
    herkunft   varchar2(3 char),
    tabelle    varchar2(5 char),
    auf_id     number(*, 0),
    status     varchar2(3 char),
    aktion     varchar2(3 char),
    ma_status  varchar2(1 char),
    ma_s_grund number(3, 0),
    ma_id      varchar2(10 char),
    lte_nr     varchar2(20 char),
    lhm_nr     varchar2(20 char),
    lagerort   varchar2(10 char),
    zlagerort  varchar2(10 char),
    menge      number(*, 3),
    menge_b    number(*, 3),
    schrott    number(*, 3),
    r_menge    number(*, 3),
    r_menge_b  number(*, 3),
    r_schrott  number(*, 3),
    stoerz_ist number(*, 12),
    ruestz_ist number(*, 12),
    prodz_ist  number(*, 12),
    ext_lie_nr varchar2(15 char),
    ext_lie_po varchar2(5 char),
    charge     varchar2(60 char),
    serie      varchar2(20 char),
    arb_pl_id  varchar2(20 char),
    ist_best   number(*, 3),
    artikel    varchar2(30 char),
    b_datum    date,
    brutto_kg  number(12, 3),
    bew_id     number(*, 0)
);


